REPLACE INTO aowow_guides (id,category,title,name,description,url,locale,status,cuFlags,userId,`date`,approveUserId,approveDate) VALUES
	 (1,3,'Lunar Festival','Lunar Festival','It''s time for the Lunar Festival, so everyone break out the fireworks, show a little respect for your elders, and come celebrate the (lunar) new year!','lunar-festival',0,3,769,0,1640991600,0,1647901298),
	 (2,3,'Noblegarden','Noblegarden','It''s time for Noblegarden, and yet another hunt for phat loot in World of Warcraft, this time in the form of brightly colored eggs!','noblegarden',0,3,769,0,1640991600,0,1647901298),
	 (3,3,'Love is in the Air','Love is in the Air','Ah, love is in the air in the World of Warcraft: sweet flowers, perfume, and sharing gifts with loved ones!','love-is-in-the-air',0,3,769,0,1640991600,0,1647901298),
	 (4,3,'Childrens Week','Childrens Week','Children''s Week is a week in which we brave face a challenge greater than any undead monstrosity, a task more daunting than saving the world. We must become parents.','childrens-week',0,3,769,0,1640991600,0,1647901298),
	 (5,3,'Midsummer Fire Festival','Midsummer Fire Festival','Midsummer is here! There are bonfires located in each major capital city (and throughout the world), which are surrounded by questgivers and merchants.','midsummer-fire-festival',0,3,769,0,1640991600,0,1647901298),
	 (6,3,'Brewfest','Brewfest','Quests completed during Brewfest will award Brewfest Prize Token which can be redeemed for items by speaking to either Blix Fixwidget or Belbi Quikswitch.','brewfest',0,3,769,0,1640991600,0,1647901298),
	 (7,3,'Hallow''s End','Hallow''s End','It''s that time again folks—time to dress up in a ridiculous costume, and go score some treats!  It''s Hallow''s End!','hallows-end',0,3,769,0,1640991600,0,1647901298),
	 (8,3,'Pilgrim''s Bounty','Pilgrim''s Bounty','It''s time to reflect on your journeys and good fortune, share plentiful food, and stories with friends.','pilgrims-bounty',0,3,769,0,1640991600,0,1647901298),
	 (9,3,'Feast of Winter Veil','Feast of Winter Veil','Deck the halls with boughs of Preserved Holly, and have a merry Winter Veil! Cheers!','winter-veil',0,3,769,0,1640991600,0,1647901298);
REPLACE INTO aowow_articles (type,typeId,locale,url,article) VALUES
    (300,1,0,'lunar-festival','[menu tab=6 path=6,3,lunar-festival]\n[div class=minibox style="text-align:left"][toc][/div]\n\n[i]It''s time for the [url=event=327]Lunar Festival[/url], so everyone break out the fireworks, show a little respect for your [url=#elders]elders[/url], and come celebrate the (lunar) new year! Festive lanterns, banners and fireworks can can be seen throughout Azeroth, where the spirits of heroes past have returned to the land. Players who visit these elders to show their respect will be nicely rewarded![/i]\n\nThe [b]Lunar Festival[/b] is held every year starting on a date that typically coincides with the Chinese New Year. The festival is celebrated by the druids of [zone=493] with great fireworks and festive attire. Ancestors of Azeroth are praised and honored by both Horde and Alliance, who then reward players with reputation and [item=21100] that can be used to purchase festive garb, patterns and fireworks!\n[h2]Elders[/h2]\n\n[img src=STATIC_URL/images/guide/lunar-festival/elders.jpg float=right border=0]Honoring elders is one of the [url=achievement=913]main activities[/url] of the festival. In 2011''s Lunar Festival, there are [b]75[/b] elders located throughout all of Azeroth (none in Outland). There are no new elders from 2010''s event.\n\n[h3]Rewards[/h3]\nFinding and honoring an elder will reward you with 75 reputation with all of your major city factions and a [item=21100], which can be used as a currency to purchase [url=#coin-of-ancestry-redemption]festival-related items[/url]. Honoring every elder will grant you 75 [item=21100], and a total of 5625 reputation. Players are reporting that you [b]will not[/b] receive this reputation bonus applied to factions you are already Honored or above with.\n\nYou will also receive a [item=21746] from each elder via in-game mail, containing either a [item=21744] or [item=21745] - so prepare for the mailbox spam! The Lucky Rocket Cluster can then be fired from a cluster launcher to gain the [spell=26522] buff!\n\n[h3]Complete List[/h3]\n\nTip: Clicking on the coordinates in the tables below will open a map of the elder''s location in a lightbox![/i]\n\n[pad]\n[div clear=both][/div]\n\n[tabs name=Elders]\n\n[tab name=Kalimdor_(26)][minibox][h2 toc=false]Legend[/h2]\n[img src=STATIC_URL/images/Mapper/pin-yellow.png border=0] [url=#ka-ka]Kalimdor[/url] (21)\n[img src=STATIC_URL/images/Mapper/pin-blue.png border=0] [url=#ka-a]Alliance[/url] (1)\n[img src=STATIC_URL/images/Mapper/pin-red.png border=0] [url=#ka-h]Horde[/url] (2)\n[img src=STATIC_URL/images/Mapper/pin-green.png border=0] [url=#ka-d]Dungeons[/url] (2)[/minibox][map zone=-6]\n[pin x=44 y=12 url=?npc=15595]Elder Bladeleaf[/pin]\n[pin x=44 y=80 url=?npc=15599]Elder Bladesing[/pin]\n[pin x=47.5 y=60.5 url=?npc=15575]Elder Bloodhoof[/pin]\n[pin x=58 y=26 url=?npc=15606]Elder Brightspear[/pin]\n[pin x=56.5 y=81 url=?npc=15586]Elder Dreamseer[/pin]\n[pin x=46 y=69 url=?npc=15581]Elder Grimtotem[/pin]\n[pin x=51 y=60.5 url=?npc=15588]Elder High Mountain[/pin]\n[pin x=43.5 y=67.5 url=?npc=15587]Elder Mistwalker[/pin]\n[pin x=53.5 y=54 url=?npc=15597]Elder Moonwarden[/pin]\n[pin x=57 y=77.5 url=?npc=15604]Elder Morningdew[/pin]\n[pin x=48 y=31.5 url=?npc=15603]Elder Nightwind[/pin]\n[pin x=41.5 y=77.5 url=?npc=15570]Elder Primestone[/pin]\n[pin x=54 y=91 url=?npc=15573]Elder Ragetotem[/pin]\n[pin x=47 y=41 url=?npc=15605]Elder Riversong[/pin]\n[pin x=59.5 y=51 url=?npc=15572]Elder Runetotem[/pin]\n[pin x=65 y=42 url=?npc=15600]Elder Skygleam[/pin]\n[pin x=53 y=74 url=?npc=15584]Elder Skyseer[/pin]\n[pin x=45 y=26.5 url=?npc=15601]Elder Starweave[/pin]\n[pin x=59 y=25 url=?npc=15574]Elder Stonespire[/pin]\n[pin x=50 y=84 url=?npc=15583]Elder Thunderhorn[/pin]\n[pin x=56 y=55 url=?npc=15582]Elder Windtotem[/pin]\n\n[pin x=40 y=11 url=?npc=15598 type=3]Elder Bladeswift[/pin]\n\n[pin x=58 y=44 url=?npc=15579 type=2]Elder Darkhorn[/pin]\n[pin x=47 y=56.5 url=?npc=15580 type=2]Elder Ezra Wheathoof[/pin]\n\n[pin x=38.5 y=58 url=?npc=15556 type=1]Elder Splitrock[/pin]\n[pin x=54.5 y=79.5 url=?npc=15578 type=1]Elder Wildmane[/pin]\n[/map]\n[h3 id=ka-ka][achievement=911] (21)[/h3]\nThese elders are located in Kalimdor.\n[pad]\n[table class=grid width=100%]\n[tr][td width=25%][b]Elder[/b][/td][td width=25%][b]Zone[/b][/td][td width=15% align=center][b]Coords[/b][/td][td][b]Location[/b][/td][/tr]\n[tr][td][npc=15595][/td][td][zone=141][/td][td align=center][lightbox=map zone=141 pins=573608]57.3, 60.8[/lightbox][/td][td]Dolanaar[/td][/tr]\n[tr][td][npc=15599][/td][td][zone=1377][/td][td align=center][lightbox=map zone=1377 pins=490377]49.0, 37.7[/lightbox][/td][td]Cenarion Hold[/td][/tr]\n[tr][td][npc=15575][/td][td][zone=215][/td][td align=center][lightbox=map zone=215 pins=483534]48.3, 53.4[/lightbox][/td][td]Bloodhoof Village[/td][/tr]\n[tr][td][npc=15606][/td][td][zone=618][/td][td align=center][lightbox=map zone=618 pins=556437]55.6, 43.7[/lightbox][/td][td]The Ruins of Kel''Theril[/td][/tr]\n[tr][td][npc=15586][/td][td][zone=440][/td][td align=center][lightbox=map zone=440 pins=513278]51.3, 27.8[/lightbox][/td][td]Gadgetzan[/td][/tr]\n[tr][td][npc=15581][/td][td][zone=357][/td][td align=center][lightbox=map zone=357 pins=767379]76.7, 37.9[/lightbox][/td][td]Lariss Pavilion[/td][/tr]\n[tr][td][npc=15588][/td][td][zone=17][/td][td align=center][lightbox=map zone=4709 pins=451579]45.1, 57.9[/lightbox][/td][td]Camp Taurajo[/td][/tr]\n[tr][td][npc=15587][/td][td][zone=357][/td][td align=center][lightbox=map zone=357 pins=626310]62.6, 31.0[/lightbox][/td][td]The Maul (PvP area in [zone=2557])[/td][/tr]\n[tr][td][npc=15597][/td][td][zone=17][/td][td align=center][lightbox=map zone=17 pins=514307]51.4, 30.7[/lightbox][/td][td]The Crossroads[/td][/tr]\n[tr][td][npc=15604][/td][td][zone=400][/td][td align=center][lightbox=map zone=400 pins=797773]79.7, 77.3[/lightbox][/td][td]Mirage Raceway[/td][/tr]\n[tr][td][npc=15603][/td][td][zone=361][/td][td align=center][lightbox=map zone=361 pins=376529]37.6, 52.9[/lightbox][/td][td]Jaedenar[/td][/tr]\n[tr][td][npc=15570][/td][td][zone=1377][/td][td align=center][lightbox=map zone=1377 pins=211105]21.1, 10.5[/lightbox][/td][td]Crystal Vale[/td][/tr]\n[tr][td][npc=15573][/td][td][zone=440][/td][td align=center][lightbox=map zone=440 pins=360801]36.0, 80.1[/lightbox][/td][td]Uldum[/td][/tr]\n[tr][td][npc=15605][/td][td][zone=331][/td][td align=center][lightbox=map zone=331 pins=356489]35.6, 48.9[/lightbox][/td][td]Astranaar[/td][/tr]\n[tr][td][npc=15572][/td][td][zone=14][/td][td align=center][lightbox=map zone=14 pins=532436]53.2, 43.6[/lightbox][/td][td]Razor Hill[/td][/tr]\n[tr][td][npc=15600][/td][td][zone=16][/td][td align=center][lightbox=map zone=16 pins=726852]72.6, 85.2[/lightbox][/td][td]Ravencrest Monument[/td][/tr]\n[tr][td][npc=15584][/td][td][zone=400][/td][td align=center][lightbox=map zone=400 pins=454500]45.4, 50.0[/lightbox][/td][td]Freewind Post[/td][/tr]\n[tr][td][npc=15601][/td][td][zone=148][/td][td align=center][lightbox=map zone=148 pins=368468]36.8, 46.8[/lightbox][/td][td]Near Auberdine[/td][/tr]\n[tr][td][npc=15574][/td][td][zone=618][/td][td align=center][lightbox=map zone=618 pins=615378]61.5, 37.8[/lightbox][/td][td]Everlook[/td][/tr]\n[tr][td][npc=15583][/td][td][zone=490][/td][td align=center][lightbox=map zone=490 pins=504761]50.4, 76.1[/lightbox][/td][td]Slithering Scar[/td][/tr]\n[tr][td][npc=15582][/td][td][zone=17][/td][td align=center][lightbox=map zone=17 pins=627367]62.7, 36.7[/lightbox][/td][td]Ratchet[/td][/tr]\n[/table]\n[h3 id=ka-a][achievement=915] (1)[/h3]\nThese elders are located in Alliance capital cities.\n[pad]\n[table class=grid width=100%]\n[tr][td width=25%][b]Elder[/b][/td][td width=25%][b]Zone[/b][/td][td width=15% align=center][b]Coords[/b][/td][td][b]Location[/b][/td][/tr]\n[tr][td][npc=15598][/td][td][zone=1657][/td][td align=center][lightbox=map zone=1657 pins=336145]33.6, 14.5[/lightbox][/td][td]Cenarion Enclave[/td][/tr]\n[/table]\n[h3 id=ka-h][achievement=914] (2)[/h3]\nThese elders are located in Horde capital cities.\n[pad]\n[table class=grid width=100%]\n[tr][td width=25%][b]Elder[/b][/td][td width=25%][b]Zone[/b][/td][td width=15% align=center][b]Coords[/b][/td][td][b]Location[/b][/td][/tr]\n[tr][td][npc=15579][/td][td][zone=1637][/td][td align=center][lightbox=map zone=1637 pins=411338]41.4, 33.8[/lightbox][/td][td]Valley of Wisdom[/td][/tr]\n[tr][td][npc=15580][/td][td][zone=1638][/td][td align=center][lightbox=map zone=1638 pins=730233]73.0, 23.3[/lightbox][/td][td]Elder Rise[/td][/tr]\n[/table]\n[h3 id=ka-d][achievement=910] (2)[/h3]\nThese elders are located inside instanced dungeons.\n[pad]\n[table class=grid width=100%]\n[tr][td width=25%][b]Elder[/b][/td][td width=25%][b]Zone[/b][/td][td width=15% align=center][b]Coords[/b][/td][td][b]Location[/b][/td][/tr]\n[tr][td][npc=15556][/td][td][zone=2100][/td][td align=center][lightbox=map zone=2100 floor=1 pins=443816]44.3, 81.6[/lightbox][/td][td]Bridge between [npc=13596] and the [npc=13601][/td][/tr]\n[tr][td][npc=15578][/td][td][zone=1176][/td][td align=center][lightbox=map zone=1176 pins=346393]Approx.[/lightbox][/td][td][npc=7273]''s room[/td][/tr]\n[/table]\n[/tab]\n\n[tab name=Eastern_Kingdoms_(24)][minibox][h2 toc=false]Legend[/h2]\n[img src=STATIC_URL/images/Mapper/pin-yellow.png border=0] [url=#ek-ek]Eastern Kingdoms[/url] (17)\n[img src=STATIC_URL/images/Mapper/pin-blue.png border=0] [url=#ek-a]Alliance[/url] (2)\n[img src=STATIC_URL/images/Mapper/pin-red.png border=0] [url=#ek-h]Horde[/url] (1)\n[img src=STATIC_URL/images/Mapper/pin-green.png border=0] [url=#ek-d]Dungeons[/url] (4)[/minibox][map zone=-3]\n[pin x=53 y=85 url=?npc=15563]Elder Bellowrage[/pin]\n[pin x=50 y=69 url=?npc=15585]Elder Dawnstrider[/pin]\n[pin x=46 y=62 url=?npc=15569]Elder Goldwell[/pin]\n[pin x=44 y=33 url=?npc=15568]Elder Graveborn[/pin]\n[pin x=53 y=40 url=?npc=15559]Elder Highpeak[/pin]\n[pin x=46 y=68 url=?npc=15567]Elder Ironband[/pin]\n[pin x=50 y=34 url=?npc=15602]Elder Meadowrun[/pin]\n[pin x=51 y=36 url=?npc=15594]Elder Moonstrike[/pin]\n[pin x=41 y=39 url=?npc=15561]Elder Obsidian[/pin]\n[pin x=51 y=71 url=?npc=15557]Elder Rumblerock[/pin]\n[pin x=51 y=61 url=?npc=15558]Elder Silvervein[/pin]\n[pin x=42 y=80 url=?npc=15577]Elder Skychaser[/pin]\n[pin x=58 y=33 url=?npc=15566]Elder Snowcrown[/pin]\n[pin x=49 y=85 url=?npc=15596]Elder Starglade[/pin]\n[pin x=45 y=75 url=?npc=15565]Elder Stormbrow[/pin]\n[pin x=54 y=34 url=?npc=15592]Elder Windrun[/pin]\n[pin x=44 y=94 url=?npc=15576]Elder Winterhoof[/pin]\n\n[pin x=47 y=59 url=?npc=15871 type=3]Elder Bronzebeard[/pin]\n[pin x=42 y=73 url=?npc=15562 type=3]Elder Hammershout[/pin]\n\n[pin x=44 y=35 url=?npc=15564 type=2]Elder Darkcore[/pin]\n\n[pin x=53 y=29 url=?npc=15607 type=1]Elder Farwhisper[/pin]\n[pin x=47 y=70 url=?npc=15549 type=1]Elder Morndeep[/pin]\n[pin x=54 y=79 url=?npc=15593 type=1]Elder Starsong[/pin]\n[pin x=48 y=70 url=?npc=15560 type=1]Elder Stonefort[/pin]\n[/map]\n[h3 id=ek-ek][achievement=912] (17)[/h3]\nThese elders are located in the Eastern Kingdoms.\n[pad]\n[table class=grid width=100%]\n[tr][td width=25%][b]Elder[/b][/td][td width=25%][b]Zone[/b][/td][td width=15% align=center][b]Coords[/b][/td][td][b]Location[/b][/td][/tr]\n[tr][td][npc=15563][/td][td][zone=4][/td][td align=center][lightbox=map zone=4 pins=579549]57.9, 54.9[/lightbox][/td][td]Dark Portal[/td][/tr]\n[tr][td][npc=15585][/td][td][zone=46][/td][td align=center][lightbox=map zone=46 pins=645240]64.5, 24.0[/lightbox][/td][td]Flame Crest[/td][/tr]\n[tr][td][npc=15569][/td][td][zone=1][/td][td align=center][lightbox=map zone=1 pins=467516]46.7, 51.6[/lightbox][/td][td]Kharanos[/td][/tr]\n[tr][td][npc=15568][/td][td][zone=85][/td][td align=center][lightbox=map zone=85 pins=619539]61.9, 53.9[/lightbox][/td][td]Brill[/td][/tr]\n[tr][td][npc=15559][/td][td][zone=47][/td][td align=center][lightbox=map zone=47 pins=500479]50.0, 47.9[/lightbox][/td][td]Creeping Ruin[/td][/tr]\n[tr][td][npc=15567][/td][td][zone=51][/td][td align=center][lightbox=map zone=51 pins=213791]21.3, 79.1[/lightbox][/td][td]Blackchar Cave[/td][/tr]\n[tr][td][npc=15602][/td][td][zone=28][/td][td align=center][lightbox=map zone=28 pins=660478]66.0, 47.8[/lightbox][/td][td]Weeping Cave[/td][/tr]\n[tr][td][npc=15594][/td][td][zone=28][/td][td align=center][lightbox=map zone=28 pins=692735]69.2, 73.5[/lightbox][/td][td]Outside of [zone=2057] (upstairs)[/td][/tr]\n[tr][td][npc=15561][/td][td][zone=130][/td][td align=center][lightbox=map zone=130 pins=450411]45.0, 41.1[/lightbox][/td][td]The Sepulcher[/td][/tr]\n[tr][td][npc=15557][/td][td][zone=46][/td][td align=center][lightbox=map zone=46 pins=831474]83.1, 47.4[/lightbox][/td][td]Dreadmaul Rock[/td][/tr]\n[tr][td][npc=15558][/td][td][zone=38][/td][td align=center][lightbox=map zone=38 pins=330460]33.0, 46.0[/lightbox][/td][td]Thelsamar[/td][/tr]\n[tr][td][npc=15577][/td][td][zone=40][/td][td align=center][lightbox=map zone=40 pins=566470]56.6, 47.0[/lightbox][/td][td]Sentinel Hill[/td][/tr]\n[tr][td][npc=15566][/td][td][zone=139][/td][td align=center][lightbox=map zone=139 pins=757546]75.7, 54.6[/lightbox][/td][td]Light''s Hope Chapel[/td][/tr]\n[tr][td][npc=15596][/td][td][zone=33][/td][td align=center][lightbox=map zone=33 pins=531184]53.1, 18.4[/lightbox][/td][td]Outside of Zul''Gurub[/td][/tr]\n[tr][td][npc=15565][/td][td][zone=12][/td][td align=center][lightbox=map zone=12 pins=398627]39.8, 62.7[/lightbox][/td][td]Goldshire[/td][/tr]\n[tr][td][npc=15592][/td][td][zone=139][/td][td align=center][lightbox=map zone=139 pins=356688]35.6, 68.8[/lightbox][/td][td]Crown Guard Tower[/td][/tr]\n[tr][td][npc=15576][/td][td][zone=33][/td][td align=center][lightbox=map zone=33 pins=265765]26.5, 76.5[/lightbox][/td][td]Booty Bay[/td][/tr]\n[/table]\n[h3 id=ek-a][achievement=915] (2)[/h3]\nThese elders are located in Alliance capital cities.\n[pad]\n[table class=grid width=100%]\n[tr][td width=25%][b]Elder[/b][/td][td width=25%][b]Zone[/b][/td][td width=15% align=center][b]Coords[/b][/td][td][b]Location[/b][/td][/tr]\n[tr][td][npc=15871][/td][td][zone=1537][/td][td align=center][lightbox=map zone=1537 pins=290170]29.0, 17.0[/lightbox][/td][td]Mystic Ward[/td][/tr]\n[tr][td][npc=15562][/td][td][zone=12][/td][td align=center][lightbox=map zone=12 pins=363660]36.3, 66.0[/lightbox][/td][td]At Stormwind City''s Gates[/td][/tr]\n[/table]\n[h3 id=ek-h][achievement=914] (1)[/h3]\nThese elders are located in Horde capital cities.\n[pad]\n[table class=grid width=100%]\n[tr][td width=25%][b]Elder[/b][/td][td width=25%][b]Zone[/b][/td][td width=15% align=center][b]Coords[/b][/td][td][b]Location[/b][/td][/tr]\n[tr][td][npc=15564][/td][td][zone=1497][/td][td align=center][lightbox=map zone=1497 pins=670380]67.0, 38.0[/lightbox][/td][td]Ruins of Lordaeron Throne Room[/td][/tr]\n[/table]\n[h3 id=ek-d][achievement=910] (4)[/h3]\nThese elders are located inside instanced dungeons.\n[pad]\n[table class=grid width=100%]\n[tr][td width=25%][b]Elder[/b][/td][td width=25%][b]Zone[/b][/td][td width=15% align=center][b]Coords[/b][/td][td][b]Location[/b][/td][/tr]\n[tr][td][npc=15607][/td][td][zone=2017][/td][td align=center][lightbox=map zone=2017 pins=762226]Approx.[/lightbox][/td][td]North section of Festival Lane (near [npc=10516])[/td][/tr]\n[tr][td][npc=15549][/td][td][zone=1584][/td][td align=center][lightbox=map zone=1584 pins=506634]Approx.[/lightbox][/td][td]Ring of Law[/td][/tr]\n[tr][td][npc=15593][/td][td][zone=1417][/td][td align=center][lightbox=map zone=1417 pins=627345]Approx.[/lightbox][/td][td]Upstairs in the dragonkin room[/td][/tr]\n[tr][td][npc=15560][/td][td]Lower [zone=1583][/td][td align=center][lightbox=map zone=1583 floor=3 pins=464462]Approx.[/lightbox][/td][td]In LBRS near the first bridge[/td][/tr]\n[/table]\n[/tab]\n\n[tab name=Northrend_(25)][minibox][h2 toc=false]Legend[/h2]\n[img src=STATIC_URL/images/Mapper/pin-yellow.png border=0] [url=#no-no]Northrend[/url] (18)\n[img src=STATIC_URL/images/Mapper/pin-green.png border=0] [url=#no-d]Dungeons[/url] (7)[/minibox][map zone=-5]\n[pin x=22.5 y=61.5 url=?npc=30364]Elder Arp[/pin]\n[pin x=77 y=51 url=?npc=30357]Elder Beldak[/pin]\n[pin x=36 y=44 url=?npc=30368]Elder Bluewolf[/pin]\n[pin x=53 y=30 url=?npc=30359]Elder Fargal[/pin]\n[pin x=57 y=37 url=?npc=30370]Elder Graymane[/pin]\n[pin x=81 y=53 url=?npc=30367]Elder Lunaro[/pin]\n[pin x=41 y=60.5 url=?npc=30358]Elder Morthie[/pin]\n[pin x=68 y=23 url=?npc=30374]Elder Muraco[/pin]\n[pin x=14 y=59 url=?npc=30360]Elder Northal[/pin]\n[pin x=17 y=64 url=?npc=30371]Elder Pamuya[/pin]\n[pin x=25 y=42 url=?npc=30362]Elder Sandrene[/pin]\n[pin x=22 y=70 url=?npc=30348]Elder Sardis[/pin]\n[pin x=42.5 y=57.5 url=?npc=30373]Elder Skywarden[/pin]\n[pin x=54 y=19 url=?npc=30375]Elder Stonebeard[/pin]\n[pin x=72 y=41 url=?npc=30369]Elder Tauros[/pin]\n[pin x=47 y=66 url=?npc=30363]Elder Thoim[/pin]\n[pin x=29 y=39 url=?npc=30365]Elder Wanikaya[/pin]\n[pin x=77.5 y=56 url=?npc=30372]Elder Whurain[/pin]\n\n[pin x=80 y=76 url=?npc=30538 type=1]Elder Chogan''gada[/pin]\n[pin x=12 y=55 url=?npc=30536 type=1]Elder Igasho[/pin]\n[pin x=81 y=76 url=?npc=30531 type=1]Elder Jarten[/pin]\n[pin x=64 y=54.5 url=?npc=30534 type=1]Elder Kilias[/pin]\n[pin x=40 y=57 url=?npc=30533 type=1]Elder Nurgen[/pin]\n[pin x=77 y=31 url=?npc=30537 type=1]Elder Ohanzee[/pin]\n[pin x=59 y=16 url=?npc=30535 type=1]Elder Yurauk[/pin]\n[/map]\n[h3 id=no-no][achievement=1396] (18)[/h3]\nThese elders are located in Northrend.\n[pad]\n[table class=grid width=100%]\n[tr][td width=25%][b]Elder[/b][/td][td width=25%][b]Zone[/b][/td][td width=15% align=center][b]Coords[/b][/td][td][b]Location[/b][/td][/tr]\n[tr][td][npc=30364][/td][td][zone=3537][/td][td align=center][lightbox=map zone=3537 pins=573437]57.3, 43.7[/lightbox][/td][td]D.E.H.T.A.[/td][/tr]\n[tr][td][npc=30357][/td][td][zone=394][/td][td align=center][lightbox=map zone=394 pins=606277]60.6, 27.7[/lightbox][/td][td]Westfall Brigade Encampment[/td][/tr]\n[tr][td][npc=30368][/td][td][zone=4197][/td][td align=center][lightbox=map zone=4197 pins=490139]49.0, 13.9[/lightbox][/td][td]Wintergrasp Fortress[/td][/tr]\n[tr][td][npc=30359][/td][td][zone=67][/td][td align=center][lightbox=map zone=67 pins=289737]28.9, 73.7[/lightbox][/td][td]Frosthold[/td][/tr]\n[tr][td][npc=30370][/td][td][zone=67][/td][td align=center][lightbox=map zone=67 pins=412847]41.2, 84.7[/lightbox][/td][td]K3[/td][/tr]\n[tr][td][npc=30367][/td][td][zone=394][/td][td align=center][lightbox=map zone=394 pins=805371]80.5, 37.1[/lightbox][/td][td]Ruins of Tethys[/td][/tr]\n[tr][td][npc=30358][/td][td][zone=65][/td][td align=center][lightbox=map zone=65 pins=297559]29.7, 55.9[/lightbox][/td][td]Star''s Rest[/td][/tr]\n[tr][td][npc=30374][/td][td][zone=67][/td][td align=center][lightbox=map zone=67 pins=646513]64.6, 51.3[/lightbox][/td][td]Camp Tunka''lo[/td][/tr]\n[tr][td][npc=30360][/td][td][zone=3537][/td][td align=center][lightbox=map zone=3537 pins=338344]33.8, 34.4[/lightbox][/td][td]Transitus Shield[/td][/tr]\n[tr][td][npc=30371][/td][td][zone=3537][/td][td align=center][lightbox=map zone=3537 pins=429496]42.9, 49.6[/lightbox][/td][td]Warsong Hold[/td][/tr]\n[tr][td][npc=30362][/td][td][zone=3711][/td][td align=center][lightbox=map zone=3711 pins=498630]49.8, 63.0[/lightbox][/td][td]River''s Heart[/td][/tr]\n[tr][td][npc=30348][/td][td][zone=3537][/td][td align=center][lightbox=map zone=3537 pins=591656]59.1, 65.6[/lightbox][/td][td]Valiance Keep[/td][/tr]\n[tr][td][npc=30373][/td][td][zone=65][/td][td align=center][lightbox=map zone=65 pins=351483]35.1, 48.3[/lightbox][/td][td]Agmar''s Hammer[/td][/tr]\n[tr][td][npc=30375][/td][td][zone=67][/td][td align=center][lightbox=map zone=67 pins=313376]31.3, 37.6[/lightbox][/td][td]Bouldercrag''s Refuge[/td][/tr]\n[tr][td][npc=30369][/td][td][zone=66][/td][td align=center][lightbox=map zone=66 pins=589560]58.9, 56.0[/lightbox][/td][td]Zim''Torga[/td][/tr]\n[tr][td][npc=30363][/td][td][zone=65][/td][td align=center][lightbox=map zone=65 pins=488782]48.8, 78.2[/lightbox][/td][td]Moa''ki Harbor[/td][/tr]\n[tr][td][npc=30365][/td][td][zone=3711][/td][td align=center][lightbox=map zone=3711 pins=638490]63.8, 49.0[/lightbox][/td][td]Rainspeaker Rapids[/td][/tr]\n[tr][td][npc=30372][/td][td][zone=394][/td][td align=center][lightbox=map zone=394 pins=642470]64.2, 47.0[/lightbox][/td][td]Camp Oneqwah[/td][/tr]\n[/table]\n[h3 id=no-d][achievement=910] (7)[/h3]\nThese elders are located inside instanced dungeons.\n[pad]\n[table class=grid width=100%]\n[tr][td width=25%][b]Elder[/b][/td][td width=25%][b]Zone[/b][/td][td width=15% align=center][b]Coords[/b][/td][td][b]Location[/b][/td][/tr]\n[tr][td][npc=30538][/td][td][zone=1196][/td][td align=center][lightbox=map zone=1196 floor=1 pins=703373]Approx.[/lightbox][/td][td]Near [npc=26693][/td][/tr]\n[tr][td][npc=30536][/td][td][zone=4265][/td][td align=center][lightbox=map zone=4265 pins=550660]Approx.[/lightbox][/td][td]To the right of [npc=26794]''s ramp[/td][/tr]\n[tr][td][npc=30531][/td][td][zone=206][/td][td align=center][lightbox=map zone=206 pins=483726]Approx.[/lightbox][/td][td]After [npc=23953][/td][/tr]\n[tr][td][npc=30534][/td][td][zone=4196][/td][td align=center][lightbox=map zone=4196 pins=529773]Approx.[/lightbox][/td][td][npc=27483]''s den[/td][/tr]\n[tr][td][npc=30533][/td][td][zone=4277][/td][td align=center][lightbox=map zone=4277 pins=211587]Approx.[/lightbox][/td][td]After [npc=28921][/td][/tr]\n[tr][td][npc=30537][/td][td][zone=4416][/td][td align=center][lightbox=map zone=4416 pins=466617]Approx.[/lightbox][/td][td]Behind the [npc=29307][/td][/tr]\n[tr][td][npc=30535][/td][td][zone=4264][/td][td align=center][lightbox=map zone=4264 pins=407699]Approx.[/lightbox][/td][td]On the way to [npc=27977][/td][/tr]\n[/table]\n[/tab]\n\n[/tabs]\n\n[h2]Quests[/h2]\n[ul]\n[li][b][url=quests&filter=na=The+Lunar+Festival]The Lunar Festival[/url][/b]\n[img src=STATIC_URL/images/guide/lunar-festival/lantern-alliance.jpg float=right border=0][b]Start:[/b] [icon name=side_horde][npc=15891][/icon] or [icon name=side_alliance][npc=15892][/icon]\n[b]End:[/b] [npc=15895]\nThis quest is simply an introductory quest available from a [icon name=side_horde][npc=15891][/icon] or [icon name=side_alliance][npc=15892][/icon], which are located in each of the major cities. The quest will send you to speak with a [npc=15895] located at the city''s main Lunar Festival camp, who will give you a new quest.[pad][/li]\n\n[li][b][quest=8867][/b]\n[b]Start & End:[/b] [npc=15895]\nTo complete this quest you must purchase fireworks from a nearby [npc=15898] and use them nearby. The large fireworks clusters (such as [item=21571]) will require use of a firework launcher, which can be found on the ground around the main Lunar Festival camps. Simply purchase and fire off the specified quantity of fireworks and return the quest to pick up the follow-up.[pad]You will receive a [item=21711] which can be used to teleport to [zone=493] by using it while standing in the ''Greater Moonlight'' (a huge, white beam of light located in the main Festival camps). Once in Moonglade, you can teleport back to any major faction city by standing in the correct beam (which are distinguished by racial revelers around each beam). This invitation does have a duration but you can get a new one from the [npc=15895] at any time during the festival.[pad][/li]\n\n[li][b][quest=8883][/b]\n[b]Start:[/b] [npc=15895]\n[b]End:[/b] [npc=15864]\nUpon arriving in [zone=493], seek out [npc=15864] who is located on the northeastern platform overlooking Lake Elune''ara. He will welcome you to Moonglade and the Lunar Festival celebration and starts some new quests. Completion of this quest may be a prerequesite for his following quests.[pad][/li]\n\n[li][b][quest=8868][/b]\n[url=?npc=15467][img src=STATIC_URL/images/guide/lunar-festival/omen.jpg float=right border=0][/url][b]Start & End:[/b] [npc=15864]\nThis quest is actually flagged as a Raid quest in-game, though it shouldn''t take very many level 70 or higher players at all to complete. Simply purchase (or acquire through quests or crafting) some rocket clusters from a [npc=15898] and head down to the Stormrage Barrow Dens in [zone=493], southeast of Lake Elune''ara. Fire off the fireworks in the nearby cluster launchers to alert the [npc=15466] to your presence. You can use the [item=21713] obtained from [quest=8862] or purchased for 10 silver from [npc=15864] to do additional damage to the Minions and Omen himself.[pad]Continue firing off rockets and defeating the Minions and eventually the demon [npc=15467] will spawn. He is a Level ?? (Boss) NPC so his actual level will most likely be 3 levels higher than the average level of your group. Even still, he is not a very difficult boss (detailed information on fighting him can be found [url=?npc=15467#comments:id=38230]here[/url]). After Omen is defeated, you must be near his corpse to obtain the [spell=26393] buff required to complete the quest. You don''t have to get credit on the kill. Receive the buff and return to Valadar to complete the quest, which rewards the nifty [item=21540] which can turn [item=7912] into [item=21536] - not amazing, but still pretty cool![/li]\n[/ul]\n\n[h2]Coin of Ancestry Redemption[/h2]\n[npc=15864] and [npc=15909] can be found in [zone=493] selling items using [item=21100] as currency. All of the items they sell are Bind of Pickup. While you can obtain only a maximum of 75 [item=21100] per year, they have no duration - so if you have some left over from a previous year''s Festival you can use them to obtain more rewards!\n\n[h3]Dumplings, Fireworks and Clothing[/h3]\n[img src=STATIC_URL/images/guide/lunar-festival/banner.jpg float=right border=0]Sold by [npc=15864]:\n[pad]\n[table class=grid width=40%]\n[tr][td][b]Item[/b][/td][td align=center width=25%][b]Cost[/b][/td][/tr]\n[tr][td][item=21537][/td][td align=center][money=0 items=21100,1][/td][/tr]\n[tr][td][item=21640][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=21157][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=21538][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=21539][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=21541][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=21544][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=21543][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[/table]\n\n[h3]Recipes[/h3]\nSold by [npc=15909]:\n[pad]\n[table class=grid width=60%]\n[tr][td][b]Item[/b][/td][td align=center width=25%][b]Cost[/b][/td][/tr]\n[tr][td][item=44916][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=44917][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=44918][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=44919][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=21740], which contains:\n[ul]\n[li][item=21724][/li]\n[li][item=21725][/li]\n[li][item=21726][/li]\n[/ul][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=21742], which contains:\n[ul]\n[li][item=21727][/li]\n[li][item=21728][/li]\n[li][item=21729][/li]\n[/ul][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=21741], which contains:\n[ul]\n[li][item=21730][/li]\n[li][item=21731][/li]\n[li][item=21732][/li]\n[/ul][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[tr][td][item=21743], which contains:\n[ul]\n[li][item=21733][/li]\n[li][item=21734][/li]\n[li][item=21735][/li]\n[/ul][/td][td align=center][money=0 items=21100,5][/td][/tr]\n[/table]\n\n[h2]Festival Goodies[/h2]\n[img src=STATIC_URL/images/guide/lunar-festival/fireworks.jpg float=right border=0]The [npc=15898] found at any major Lunar Festival camp sells an assortment of fireworks, as well an alcoholic beverage with an interesting side-effect!\n[pad]\n[table class=grid width=40%]\n[tr][td][b]Item[/b][/td][td align=center width=25%][b]Cost[/b][/td][/tr]\n[tr][td][item=21721][/td][td align=center][money=15][/td][/tr]\n[tr][td][item=21558][/td][td align=center][money=25][/td][/tr]\n[tr][td][item=21559][/td][td align=center][money=25][/td][/tr]\n[tr][td][item=21557][/td][td align=center][money=25][/td][/tr]\n[tr][td][item=21571][/td][td align=center][money=100][/td][/tr]\n[tr][td][item=21574][/td][td align=center][money=100][/td][/tr]\n[tr][td][item=21576][/td][td align=center][money=100][/td][/tr]\n[tr][td][item=21747][/td][td align=center][money=300][/td][/tr]\n[/table]\n[pad]\n\nSold by [npc=15864]:\n[pad]\n[table class=grid width=40%]\n[tr][td][b]Item[/b][/td][td align=center width=25%][b]Cost[/b][/td][/tr]\n[tr][td][item=21713][/td][td align=center][money=1000][/td][/tr]\n[/table]\n\n[h2]Achievements[/h2]\n\n[ul]\n[li][img src=STATIC_URL/images/guide/lunar-festival/lantern-horde.jpg float=right border=0][b][achievement=913][/b]\nThis achievement can be found in the main World Events achievement category and is awarded upon completion of every one of the Lunar Festival achievements. This achievement awards the player title ''Elder'' and is a requirement towards completion of [achievement=2145] ([url=achievement=2144]Alliance version[/url]) which rewards the beautiful [item=44177].[pad][/li]\n\n[li][b][achievement=605][/b]\n[b][small]Receive a Coin of Ancestry.[/small][/b]\nTo complete this achievement, simply acquire a single [item=21100]. This achievement has five different ranks, awarding achievements for [achievement=606], [achievement=607], [achievement=608] and finally [achievement=609]. Coins are acquired by completing the quests available from elders found in different zones (see tabs [url=#elders]above[/url]).[pad]\n[/li]\n\n[li][b][achievement=912][/b]\n[b][small]Honor the Elders which are located in Eastern Kingdoms.[/small][/b]\nFor this achievement, you must honor all 17 elders found throughout the Eastern Kingdoms. For elder locations, refer to the tabs [url=#elders]above[/url]![pad][/li]\n\n[li][b][achievement=911][/b]\n[b][small]Honor the Elders which are located in Kalimdor.[/small][/b]\nFor this achievement, you must honor all 21 elders found throughout Kalimdor. For elder locations, refer to the tabs [url=#elders]above[/url]![pad][/li]\n\n[li][b][achievement=1396][/b]\n[b][small]Honor the Elders which are located in Northrend.[/small][/b]\nFor this achievement, you must honor all 18 elders found throughout Northrend (and, incidentally, you must also have the Wrath of the Lich King expansion). For elder locations, refer to the tabs [url=#elders]above[/url]![pad][/li]\n\n[li][b][achievement=910][/b]\n[b][small]Honor the Elders which are located inside the dungeons.[/small][/b]\nFor this achievement, you must honor all 13 elders found inside various dungeons of Eastern Kingdoms, Kalimdor and Northrend. For elder locations, refer to the tabs [url=#elders]above[/url]![pad][/li]\n\n[li][b][achievement=915][/b]\n[b][small]Honor the Elders which are located in the Alliance capital cities.[/small][/b]\nFor this achievement, you must honor all 3 elders located in major Alliance cities. As the elders are friendly to both factions, this achievement is able to be completed by both Horde and Alliance players. For elder locations, refer to the tabs [url=#elders]above[/url]![pad][/li]\n\n[li][b][achievement=914][/b]\n[b][small]Honor the Elders which are located in the Horde capital cities.[/small][/b]\nFor this achievement, you must honor all 3 elders located in major Horde cities. As the elders are friendly to both factions, this achievement is able to be completed by both Horde and Alliance players. For elder locations, refer to the tabs [url=#elders]above[/url]![pad][/li]\n\n[li][b][achievement=937][/b]\n[b][small]Complete the Elune''s Blessing quest by defeating Omen.[/small][/b]\nTo complete this achievement, you must complete the quest [quest=8868] available from [npc=15864] in [zone=493]. This achievement does not actually require you to summon or defeat [npc=15467], but just to obtain the [spell=26393] buff by being near him when he is defeated (by other players or your own group).[pad][/li]\n\n[li][b][achievement=1552][/b]\n[b][small]Shoot off 10 Festival Firecrackers in 30 seconds or less.[/small][/b]\nTo complete this achievement, simply purchase 10 [item=21747] from a [npc=15898] located at a Lunar Festival camp in [zone=1537], [zone=1657], [zone=1638], [zone=1637], [zone=1497] or [zone=493]. Once you have obtained the fireworks, just hotkey them and fire them off as quickly as possible! Easy![pad][/li]\n\n[li][b][achievement=626][/b]\n[b][small]Purchase a festive pant suit or festive dress with Coins of Ancestry.[/small][/b]\nTo complete this achievement, you must purchase either a festive pant suit or festive dress from [npc=15864] with [item=21100] obtained from honoring the elders. The festival clothing can be purchased for 5 [item=21100]. There are three different dresses and three different pant suits that can be purchased, so you can get all of them to complete your very own Lunar Festival wardrobe (though the achievement does only require one). The clothing is Bind on Pickup, but items can be purchased by characters of any level so this is a great opportunity to deck out your bank alt in style![pad][/li]\n\n[li][b][achievement=1281][/b]\n[b][small]Shoot off 10 Red Rocket Clusters in 25 seconds or less.[/small][/b]\nTo complete this achievement, simply purchase 10 [item=21576] from a [npc=15898] located at a Lunar Festival camp in [zone=1537], [zone=1657], [zone=1638], [zone=1637], [zone=1497] or [zone=493]. Unlike other fireworks, cluster fireworks must be launched from a [item=21570], which you can find on the ground throughout the camps or even have one crafted by an engineer (though that isn''t really necessary). Find a launcher and fire away![/li]\n[/ul]'),
    (300,2,0,'noblegarden','[menu tab=6 path=6,3,noblegarden]\n\n[i]It''s time for [url=/?event=181]Noblegarden[/url], and yet another hunt for phat loot in World of Warcraft, this time in the form of brightly colored eggs! We join together to "share the joy of life and friendship" all the while meticulously hunting carefully hidden eggs and nomming tons of chocolate![/i]\n\nEggs have been hidden all across the places of our youth (namely, the starting areas for the Alliance and Horde races) for both young and old to discover and perhaps even be rewarded with a [url=/?item=44794]fabulous[/url] [url=/?item=44803]prize[/url]! Simply head out to one of your faction''s starting areas, grab some quests, and get out there and hunt eggs! Maybe you''ll even earn some [url=#achievements]achievements[/url] (and a title) along the way!\n\n[div class=minibox style="text-align:left; clear:right"][toc][/div]\n\n[h2]Quests[/h2]\n\n[ul]\n[li][icon name=side_horde][b][quest=13483][/b][/icon] or [icon name=side_alliance][b][quest=13484][/b][/icon]\n[b]Start:[/b] Commoners found in the various cities\n[b]End:[/b] [icon name=side_horde][npc=32798][/icon] or [icon name=side_alliance][npc=32799][/icon]\nThis quest is simply a breadcrumb quest, leading players from major cities to a Noblegarden camp, which can be found in the Horde or Alliance starting areas. For Horde, these areas include Bloodhoof Village, Brill, Falconwing Square, and Razor Hill. For Alliance, these areas include Azure Watch, Dolanaar, Goldshire, or Kharanos. Travel to any of them and speak to the [icon name=side_horde][npc=32798][/icon] or [icon name=side_alliance][npc=32799][/icon] to obtain a daily quest.\n[ul]\n[li][url=/?item=44802][img src=STATIC_URL/images/guide/noblegarden/basket.jpg border=0 float=right][/url][icon name=side_horde][b][quest=13479][/b][/icon] or [icon name=side_alliance][b][quest=13480][/b][/icon]\n[b]Start & End:[/b] [icon name=side_horde][npc=32798][/icon] or [icon name=side_alliance][npc=32799][/icon]\nThis quest is a daily quest, asking players to collect 20 [item=44806] in exchange for a [item=44792] and [money=74000]. [item=44806] can be found inside [item=45072] looted throughout the starting zones.[pad][/li]\n[/ul][/li]\n\n[li][icon name=side_horde][b][quest=13503][/b][/icon] or [icon name=side_alliance][b][quest=13502][/b][/icon]\n[b]Start & End:[/b] [icon name=side_horde][npc=32837][/icon] or [icon name=side_alliance][npc=32836][/icon]\nThis quests gives you an [item=44802] to aid you in collecting 10 [item=44791] from [url=/?object=113768]Brightly Colored Eggs[/url]. Once you''ve got the chocolates, turn them in and you will be rewarded with a [item=45067] which you can use for a temporary speed boost in any of the starting zones that [url=/?object=113768]Brightly Colored Eggs[/url] can be found. This item has only a ten second cooldown.\n[pad]\nTip: The basket that is rewarded is exactly the same as the one you are provided with for the quest. Unless you have extra chocolates, you should probably not complete the quest.[/li][/ul]\n\n[h2]Hunting for Eggs![/h2]\n\n[div float=right align=right][url=/?item=45072][img src=STATIC_URL/images/guide/noblegarden/eggs.jpg border=0][/url]\n[small][color=red]Warning:[/color] Eggs are smaller than they appear.[/small][/div]\n\nPlayers will once again be scurrying to hunt down [url=/?object=113768]Brightly Colored Eggs[/url] that spawn hidden in the [b]starting areas[/b] of Azeroth:\n\n[ul]\n[li][icon name=side_alliance][b]Alliance:[/b][/icon] Azure Watch, Dolanaar, Goldshire, and Kharanos[/li]\n[li][icon name=side_horde][b]Horde:[/b][/icon] Bloodhoof Village, Brill, Falconwing Square, and Razor Hill[/li]\n[/ul]\n\nEggs can be found [i]only[/i] in the starting areas. Blizzard has increased the spawn rate of the eggs, thankfully, and this year you''ll have an entire week to hunt them instead of just one day. This should give most players more than enough time to collect all of the new treasures offered in this year''s Noblegarden.\n\nThe main item players will be collecting from the [item=45072] looted within is basically the "currency" of the Noblegarden event - [item=44791] - which most every egg will contain. Expect to collect a lot of them, as they are not only a currency used to purchase items from Noblegarden vendors but there are achievements for actually [i]consuming[/i] quantities of the chocolates as well!\n\nThankfully, all of the items available from the vendors can also randomly be looted from a [url=/?object=113768]Brightly Colored Egg[/url] so you may get lucky! Likewise, if you''re not so lucky you''ll have your chance to purchase the items from the vendor in exchange for chocolate - one of the first win-win holidays in Azerothian history! Take that, random loot!\n\n[h2]Noblegarden Goodies[/h2]\n\nNoblegarden features a small assortment of festive items which can be purchased from a Noblegarden Vendor or Noblegarden Merchant (found in one of your faction''s starting towns) in exchange for [item=44791]. Or, you may get lucky and find one or more of these items while egg hunting!\n\n[url=/?item=45073][img src=STATIC_URL/images/guide/noblegarden/flowers.jpg float=right border=0][/url]Here are the items you can buy with [item=44791]s:\n\n[pad]\n\n[table class=grid width=40%]\n[tr][td][b]Item[/b][/td][td align=center width=25%][b]Cost[/b][/td][/tr]\n[tr][td][item=44818][/td][td align=center][money=0 items=44791,5][/td][/tr]\n[tr][td][item=44792][/td][td align=center][money=0 items=44791,10][/td][/tr]\n[tr][td][item=45073][/td][td align=center][money=0 items=44791,50][/td][/tr]\n[tr][td][item=44800][/td][td align=center][money=0 items=44791,50][/td][/tr]\n[tr][td][item=6833][/td][td align=center][money=0 items=44791,25][/td][/tr]\n[tr][td][item=6835][/td][td align=center][money=0 items=44791,25][/td][/tr]\n[tr][td][item=19028][/td][td align=center][money=0 items=44791,50][/td][/tr]\n[tr][td][item=44803][/td][td align=center][money=0 items=44791,50][/td][/tr]\n[tr][td][item=44794][/td][td align=center][money=0 items=44791,100][/td][/tr]\n[tr][td][div float=right margin=0px][small][color=c8]Mage[/color][/small][/div][item=44793][/td][td align=center][money=0 items=44791,100][/td][/tr]\n[/table]\n\n[pad]\n\nIn order to purchase all of the items available from the Noblegarden vendors (excluding the mage-only book) you will need a total of [b]365[/b] [item=44791]. You will need an additional [b]100[/b] [item=44791] to complete the two chocolate-consuming related achievements, and [b]10[/b] [item=44791] to complete [quest=13502] so estimate that you should collect at least [b]475[/b] [item=44791]. That is, of course, assuming that you don''t find any of the vendor items while hunting eggs - after opening that many eggs I hope at least a few show up!\n\nIt is important to remember that you have a chance to find nearly all of the items required for achievements contained in [item=45072], with the exception of the [item=44818] required for [achievement=2420] ([url=achievement=2421]Alliance Version[/url]). The [item=6833], [item=6835], [item=44800], [item=45073] and [item=44794] can all be found inside [item=45072] and the [item=44792] is available as a reward from the daily quest [quest=13479] ([url=quest=13480]Alliance version[/url]). This brings the total number of [item=44791] [i]required[/i] down to only [b]105[/b]!\n\n\n[h2]Achievements[/h2]\n\n[ul]\n[li][url=/?item=44794][img src=STATIC_URL/images/guide/noblegarden/rabbit.gif border=0 float=right][/url][b][icon name=side_horde][achievement=2798][/icon][/b] or [b][icon name=side_alliance][achievement=2797][/icon][/b]\nThis achievement can be found in the main World Events achievement category and is awarded upon completion of every one of the Noblegarden achievements [i]except[/i] [url=/?achievement=249]Dressed For The Occasion[/url] and [url=/?achievement=248]Sunday''s Finest[/url]. This achievement awards the player title [b]''the Noble''[/b] and is a requirement towards completion of [achievement=2145] ([url=?achievement=2144]Alliance version[/url]) which rewards the beautiful [spell=60024].[pad][/li]\n\n[li][b][achievement=2576][/b]\nFor this achievement, you must kiss another player (male or female, it doesn''t matter) who is wearing an [item=19028] while you are wearing a [item=6833] and [item=6835]. These clothes can be found randomly in a [item=45072] or purchased from a vendor in exchange for [item=44791]. Note that the achievement is only awarded to the player wearing the Tuxedo set (and that this Tuxedo set is different than the tailor-crafted set), so in order to complete the achievement you will have to purchase the [item=6833] and [item=6835] yourself while another player can have the [item=19028]. Since these items are not bind on pickup, however, you can opt to simply trade clothes with a friend and take turns getting the achievement.[pad][/li]\n\n[li][b][achievement=2417][/b]\nFor this achievement you must eat 25 [item=44791] discovered inside [url=/?object=113768]Brightly Colored Eggs[/url]. Make sure you still save enough to buy goodies from the vendor![pad][/li]\n\n[li][b][achievement=2418][/b]\nFor this achievement you must eat 100 [item=44791] discovered inside [item=45072]. Since this is a meta achievement, you only need an additional 75 [item=44791] after the first 25 you consumed for [url=/?achievement=2417]Chocolate Lover[/url]. Once again, make sure you collect enough chocolates to nab this achievement and still be able to buy goodies from the vendor![pad][/li]\n\n[li][b][achievement=2436][/b]\nFor this achievement, you must first obtain the [item=44800] either from a [item=45072] or purchased from a vendor for 50 [item=44791]. Simply equip the robes and you can activate it''s ''Use'' ability, which in this case plants a flower where you stand! Once you''ve got the robes on, simply travel to each of these five deserts - [zone=3], [zone=405], [zone=1377], [zone=440] and [zone=400] - and plant a flower.[pad][/li]\n\n[li][b][achievement=249][/b]\nThis luck-based achivement is awarded upon discovering an [item=19028] inside a [object=113768]. This achievement is (thankfully) not a requirement for the meta-achievement [achievement=2798] ([url=?achievement=2797]Alliance version[/url]).[pad][/li]\n\n[li][b][achievement=2416][/b]\nFor this achievement you must lay an egg (!) in the Golakka Hot Springs of [zone=490] while polymorphed into a [spell=61734]! There are two different ways to become a Noblegarden Bunny. The easy way is to have another player travel with you and use a [item=44792] to change you into a rabbit. Simply stand around long enough and eventually your rabbit will lay an egg - voila, achievement done. The more complicated way is to open [url=/?object=113768]Brightly Colored Eggs[/url] until you are randomly transformed into a [spell=61734]. Then, good luck getting to Un''goro. The most logical way to get there (assuming a level 80 character who isn''t an engineer):[ul]\n[li][b]1.[/b] Get transformed into a rabbit.[/li]\n[li][b]2.[/b] Hearth to [url=/?zone=4395]Dalaran[/url] or Gadgetzan.[/li]\n[li][b]3.[/b] If you hearthed to Dalaran, take the portal to [url=/?zone=1941]Caverns of Time[/url] located inside the Violet Citadel.[/li]\n[li][b]4.[/b] Run across [zone=440] to [zone=490], praying not to get in combat because damage will break the diguise. Oh, and you can''t mount or taxi, either, so the run will take you close to 15 minutes. Swimming won''t remove your rabbit costume.[/li]\n[li][b]5.[/b] Sit anywhere at the Golakka Hot Springs for a few seconds, until you lay an egg.[/li]\n[/ul]\nObviously, the method stated first is much, much easier and way more practical![pad]\n[/li]\n\n[li][b][achievement=2676][/b]\nFor this achievement you must simply loot a [item=45072] from inside a [object=113768], found in any starting zone in Azeroth.[pad][/li]\n\n[li][b][icon name=side_horde][achievement=2420][/icon][/b] or [b][icon name=side_alliance][achievement=2421][/icon][/b]\nFor this achievement you must hide a [item=44818] anywhere in Silvermoon City (if you''re Horde) or Stormwind City (if you''re Alliance). These eggs can be purchased from the Noblegarden vendors for 5 [item=44791], and you can then loot the egg yourself to get a [item=44791] back (and maybe something else)![pad][/li]\n\n[li][url=/?item=44803][img src=STATIC_URL/images/guide/noblegarden/ears.jpg border=0 float=right][/url][b][achievement=2422][/b]\nFor this achievement you must use [item=45073] to place bunny ears on a female of each race that is level 18 or higher. [item=45073] can be purchased from a Noblegarden vendor for 50 [item=44791] or may be randomly looted from a [item=45072]. While finding females of every race may not be very difficult, the item has a 5 minute cooldown. So, girls, prepare to be stalked by weirdos waving flowers in your general direction while they wait for the cooldown to come up.[pad][/li]\n\n[li][b][icon name=side_horde][achievement=2497][/icon][/b] or [b][icon name=side_alliance][achievement=2419][/icon][/b]\nThis achievement requires that you have first obtained the [item=44794], either by looting it randomly from a [item=45072] or purchasing it from a Noblegarden vendor for 100 [item=44791]. Once you have done that, head out to each of the four starting areas for your faction and find another player with a Spring Rabbit. After a few moments of the rabbits noticing each other, the magic will happen! No spoilers, but ha ha, "like rabbits" and all that - let''s keep things PG-13 and pretend we''re all mature enough to simply have a chuckle at Blizzard''s little joke. Anyway, do this at all four starting areas and you''re done![pad][/li]\n\n[li][b][achievement=248][/b]\nThis luck-based achivement is awarded upon discovering both the [item=6833] and the [item=6835] inside a [object=113768]. This achievement is (thankfully) not a requirement for the meta-achievement [achievement=2798] ([url=?achievement=2797]Alliance version[/url]).[/li]\n[/ul]'),
    (300,3,0,'love-is-in-the-air','[menu tab=6 path=6,3,love-is-in-the-air]\n\n[div float=right]\n[url=/?item=50250][img src=STATIC_URL/images/guide/love-is-in-the-air/rocket.jpg border=0][/url]\n[/div]\n\n[i]Ah, [url=/?event=335]love is in the air[/url] in the World of Warcraft: sweet flowers, perfume, and sharing gifts with loved ones! But, what''s this? A sinister plot is afoot involving some shady goblin newcomers to the seasonal market -- the Crown Chemical Company! It''s up to us to help save Azeroth from their chemically altered goods all while spreading love and appreciation to our faction leaders and fellow players![/i]\n\nThis holiday can be celebrated by the [icon name=side_horde]Horde[/icon] in [zone=1637] and the [icon name=side_alliance]Alliance[/icon] in [zone=1519]. Seasonal decorations such as wreaths, candles and ribbons can be found in all major cities and at most zone inns. New [npc=37674]s have been added selling seasonal gifts and goodies.\n\n[h2]Quests[/h2]\n\n[div class=minibox style="text-align:left;  clear:right"][toc][/div]\n\n2010''s Love is in the Air event has been completely re-done, so there are a number of new quests (including daily quests) players can complete to obtain [item=49927] used to purchase holiday items.\n\n[h3]Main Questline[/h3]\n\nA new questline has been added in 2010''s Love is in the Air event involving the Steamwheedle Cartel and the Crown Chemical Company. The Steamwheedle Cartel suspects there''s something shady about these goblin newcomers, and investigators have been hired to get to the bottom of things - with your help! The final quest of this chain leads directly into the quest unlocking the daily quest to fight [npc=36296], though I am not sure yet if this quest chain is [i]required[/i].\n\n[ul]\n[li][icon name=side_horde][b][quest=24805][/b][/icon] or [icon name=side_alliance][b][quest=24804][/b][/icon]\n[b]Start:[/b] [npc=38295]\n[b]End:[/b] [icon name=side_horde][npc=37172][/icon] or [icon name=side_alliance][npc=38066][/icon]\nA Junior Detective located near the Crown Chemical Co. camps ask Horde players to head out to [zone=1637] to find [npc=37172] and let him know you''re interested in helping the Steamwheedle Cartel investigate the Crown Chemical Co. and their actions. Alliance players are sent to meet Inspector Snip Snagglebolt in [zone=1519].[pad]\n[img src=STATIC_URL/images/guide/love-is-in-the-air/ribbon.jpg border=0 float=right][ul]\n[li][icon name=side_horde][b][quest=24536][/b][/icon] or [icon name=side_alliance][b][quest=24655][/b][/icon]\n[b]Start & End:[/b] [icon name=side_horde][npc=37172][/icon] or [icon name=side_alliance][npc=38066][/icon]\nThe goblin investigator will provide you with [item=50131] which you must use to test the air around 6 heavily perfumed guards found throughout the city. Simply use the item on the guards and return to the investigator.[pad]\n[ul]\n[li][icon name=side_horde][b][quest=24541][/b][/icon] or [icon name=side_alliance][b][quest=24656][/b][/icon]\n[b]Start & End:[/b] [icon name=side_horde][npc=37172][/icon] or [icon name=side_alliance][npc=38066][/icon]\nFor this quest, the goblins will have you disguise yourself as a package runner for the Crown Chemical Co., and you must head outside either [zone=1637] or [zone=1519] where you''ll find a stockpile of the Company''s goods. Quickly run by it to have the [item=49867] handed off to you before they notice you aren''t really on their side, and bring it back to the investigator. For Horde players, the parcels can be found to the left outside of Orgrimmar tucked away in a corner near the city wall. It''s best to go find the parcel camps first before accepting the quest as the goblin disguise has only a 2 minute duration during which you are stuck sprinting on foot.[pad]\n[ul]\n[li][icon name=side_horde][b][quest=24850][/b][/icon] or [icon name=side_alliance][b][quest=24848][/b][/icon]\n[b]Start:[/b] [icon name=side_horde][npc=37172][/icon] or [icon name=side_alliance][npc=38066][/icon]\n[b]End:[/b] [icon name=side_horde][npc=38328][/icon] or [icon name=side_alliance][npc=38325][/icon]\nTurns out this crate you retrieved contained some sort of chemical-filled rockets, which the goblins recognize as having been crafted by [npc=37715]. You are sent out to find Snivel''s alleged girlfriend to get as much information as you can on his wherabouts. Horde players are sent to [npc=38328], at Gotri''s Travelling Goods in [zone=1637]''s Drag while Alliance players can find Marion Sutton at the Gilded Rose in [zone=1519]''s Trade District[pad]\n[ul]\n[li][icon name=side_horde][b][quest=24851][/b][/icon] or [icon name=side_alliance][b][quest=24849][/b][/icon]\n[b]Start & End:[/b] [icon name=side_horde][npc=38328][/icon] or [icon name=side_alliance][npc=38325][/icon]\nWell, turns out Snivel has flown the coop! The distraught (but mostly annoyed) ladies send you on a hunt for that lying goblin Snivel and have you search the bank, auction house and barber shop of your faction''s respective city ([zone=1637] or [zone=1519]). [pad]\n[ul]\n[li][icon name=side_horde][b][quest=24576][/b][/icon] or [icon name=side_alliance][b][quest=24657][/b][/icon]\n[b]Start:[/b] [icon name=side_horde][npc=38328][/icon] or [icon name=side_alliance][npc=38325][/icon]\n[b]End:[/b] [npc=37715]\nAfter no luck finding the goblin on any of his errands, the ladies suspect that he''s now on his way out for a nice escape to the South Seas - you''ve got to stop him! Horde players must head out to the East zeppelin tower (the one that leads to Eastern Kingdoms) and Alliance players to the Stormwind Harbor in attempt to stop Snivel and get some information before he''s gone for good. Simply talk to him and you''ll get [item=49915]. Bring this Ledger back to Snip or Snap and this chain leads into [icon name=side_horde][b][quest=24793][/b][/icon] or [icon name=side_alliance][b][quest=24792][/b][/icon], and the inevitable defeat of Apothecary Hummel, the new event boss.\n[/li][/ul][/li][/ul][/li][/ul][/li][/ul][/li][/ul][/li][/ul]\n[ul]\n[li][icon name=side_horde][b][quest=14483][/b][/icon] or [icon name=side_alliance][b][quest=24745][/b][/icon]\n[b]Start:[/b] [icon name=side_horde][item=49641][/icon] or [icon name=side_alliance][item=50320][/icon]\n[b]End:[/b] [icon name=side_horde][npc=37172][/icon] or [icon name=side_alliance][npc=38066][/icon]\nUpon making it to Shadowfang Keep and discovering the Apothecaries within, players will receive this greeting card detailing the Crown Chemical Co.''s plans to infect all of Azeroth with their perfumed plague (and gain back their established market exploiting holidays for gold)! Simply bring it to Snap or Snip and the quest chain ends rather abruptly and unceremoniously. The end![/li]\n[/ul]\n\n[h3]Random Daily Quests[/h3]\n\n[img src=STATIC_URL/images/guide/love-is-in-the-air/candle.jpg border=0 float=right]The Crown Chemical Company would like for you to share their new products with the denizens of Azeroth to help establish their role as a new provider of quality holiday goods. Three daily quests have been added asking users to sample their new holiday products with players. One of these daily quests will be randomly available each day of the event. Those hearts you''re seeing everywhere are the result of players who have sampled one of the Chemical Company''s products - therefore, any quest item used on a player with a heart (and [spell=69438] debuff) will not grant quest credit.\n[ul]\n[li][b][quest=24635][/b]\n[b]Start & End:[/b] [npc=37675]\nThe Crown Chemical Company would like you to test out their [item=49668] on 10 different people. You will be rewarded with 5x [item=49927].[pad][/li]\n[li][b][quest=24629][/b]\n[b]Start & End:[/b] [npc=37675]\nThe Crown Chemical Company would like you to test out their [item=49669] on 10 different people. You will be rewarded with 5x [item=49927].[pad][/li]\n[li][b][quest=24636][/b]\n[b]Start & End:[/b] [npc=37675]\nThe Crown Chemical Company would like you to toss samples from the [item=49670] to 10 different people. You will be rewarded with 5x [item=49927].[/li]\n[/ul]\n\n[h3]Daily: Crushing the Crown[/h3]\n\nThe Steamwheedle Cartel need all the help they can get in eradicating the Crown Chemical Co. and their sinister plot. Players level 5 and higher can obtain a daily quest pitting them against mobs their level. The quest you get is dependent on your current level, and your faction. For this daily, you must kill 5 of the Crown NPCs in the designated zone and use [item=50130] to destroy a nearby chemical wagon.\n\n[icon name=side_horde][b]Horde[/b][/icon]\n[b]Start & End:[/b] [npc=37172]\n[ul]\n[li][b][quest=24638][/b] [b](Level 5)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24645][/b] [b](Level 14)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24647][/b] [b](Level 23)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24648][/b] [b](Level 32)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24649][/b] [b](Level 41)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24650][/b] [b](Level 51)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24651][/b] [b](Level 61)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24652][/b] [b](Level 71)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[/ul]\n\n[icon name=side_alliance][b]Alliance[/b][/icon]\n[b]Start & End:[/b] [npc=38066]\n[ul]\n[li][b][quest=24658][/b] [b](Level 5)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24659][/b] [b](Level 14)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24660][/b] [b](Level 23)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24662][/b] [b](Level 32)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24663][/b] [b](Level 41)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24664][/b] [b](Level 51)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24665][/b] [b](Level 61)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[li][b][quest=24666][/b] [b](Level 71)[/b] - Repeatable daily quest. Awards [item=49927] x5 and a sum of money[/li]\n[/ul]\n\n[h3]Daily: Gifts to Faction Leaders[/h3]\n\n[img src=STATIC_URL/images/guide/love-is-in-the-air/wreath.jpg border=0 float=right]This year, instead of the complicated Gift Collections being gathered and presented to the respective faction leaders, players will instead be asked to create and turn in [item=49916]s. These bracelets can be created by obtaining a [item=49661], which you can get from Kwee Q. Peddlefeet located near the Crown Chemical Co.''s camp, found outside of auction houses in each of the major cities.\n\nOnce you have obtained this item, you will then be able to gather [item=49655]s from "worthwhile enemies" - any enemy you kill that is "honorable" (green or higher difficulty) has a chance to create a [item=49655]. At this time, you must land the killing blow on the enemy in order to gain a Charm. Combining 10 [item=49655]s will create a single Lovely Charm Bracelet, which, upon accepting a daily quest, can be turned in to the faction leader of your choice. You can turn in each of the four faction leader daily quests once per day.\n\n[icon name=side_horde][b]Horde[/b][/icon]\n[b]Start:[/b] Kwee Q. Peddlefeet\n[b]End:[/b] Faction leader of your choice (depends on quest)\n[ul]\n[li][b][quest=24612][/b] - Repeatable daily quest. Awards [item=49927] x5 and a [item=49939][/li]\n[li][b][quest=24613][/b] - Repeatable daily quest. Awards [item=49927] x5 and a [item=49937][/li]\n[li][b][quest=24614][/b] - Repeatable daily quest. Awards [item=49927] x5 and a [item=49941][/li]\n[li][b][quest=24615][/b] - Repeatable daily quest. Awards [item=49927] x5 and a [item=49943][/li]\n[/ul]\n\n[icon name=side_alliance][b]Alliance[/b][/icon]\n[b]Start:[/b] Kwee Q. Peddlefeet\n[b]End:[/b] Faction leader of your choice (depends on quest)\n[ul]\n[li][b][quest=24597][/b] - Repeatable daily quest. Awards [item=49927] x5 and a [item=49936][/li]\n[li][b][quest=24609][/b] - Repeatable daily quest. Awards [item=49927] x5 and a [item=49940][/li]\n[li][b][quest=24610][/b] - Repeatable daily quest. Awards [item=49927] x5 and a [item=49938][/li]\n[li][b][quest=24611][/b] - Repeatable daily quest. Awards [item=49927] x5 and a [item=49942][/li]\n[/ul]\n\n[h2]Boss: Apothecary Hummel[/h2]\n\nAlso new to this year''s Love is in the Air celebration is the of a special, event-only boss located in [zone=209] - [b]Apothecary Hummel[/b]! This boss can be battled upon completion of a short quest chain, though it is likely that the first step need not be completed and you can just accept the quest outside of Shadowfang Keep and zone in to complete it. The boss will respawn immediately after being killed, so every member of your party will be able to summon and kill the boss once for the daily quest without having to reset the instance.\n\n[h3]Related Quests[/h3]\n\n[ul]\n[li][icon name=side_horde][b][quest=24793][/b][/icon] or [icon name=side_alliance][b][quest=24792][/b][/icon]\n[b]Start:[/b] [icon name=side_horde][npc=37172][/icon] or [icon name=side_alliance]Inspector Snip Snagglebolt[/icon]\n[b]End:[/b] [npc=38208]\nAfter completing the quest [b][quest=24576][/b] ([url=/?quest=24657]Alliance version[/url]), you will receive [item=49915] to return to [icon name=side_horde][npc=37172][/icon] or [icon name=side_alliance]Inspector Snip Snagglebolt[/icon]. Upon doing so, you will be able to obtain this quest, asking you to head out to [zone=209] and speak to [npc=38208].[pad][ul]\n[li][b][quest=14488][/b]\n[b]Start:[/b] [npc=38208]\n[b]End:[/b] [npc=36296]\n[npc=38208] will give you a [item=49635] to serve to [npc=36296], located deep inside [zone=209]. The [item=49631] he gives also includes two items which are used in the fight against the Apothecary and his minions. This quest can be completed once per day, similar to other event boss summons.[/li]\n[/ul][/li]\n[/ul]\n\n[h3]Fight Overview[/h3]\n\n[npc=36296], [npc=36565] and [npc=36272] can be found in Shadowfang Keep at the main "outdoor" area of the keep, near the stabled horses. The fight is fairly straightforward, and seems much more confusing than it really is. Open the provided [item=49631] and you will find three items: [item=49351], [item=49352] and the [item=49635]. The [item=49635] is what you turn in to the Apothecary to start the encounter.\n\nFirst, select either the cologne or perfume and use it. This will apply a buff that negates all damage from the chosen source.\n[ul]\n[li][item=49351] creates a purple aura and makes you immune to [spell=68641] and [spell=68607].[/li]\n[li][item=49352] creates a green aura and makes you immune to [spell=68946] and [spell=68948].[/li]\n[/ul]\n\nThere are three total apothecaries in the encounter:\n[ul]\n[li][npc=36296] - Uses [spell=68641] and has the melee-range aura [spell=68607]. His damage can be nullified by use of [item=49351].[/li]\n[li][npc=36565] - Uses [spell=68946] and and has the melee-range aura [spell=68948]. His damage can be nullified by use of [item=49352].[/li]\n[li][npc=36272] - Runs around throwing bottles of perfume and cologne on the ground, creating dangerous clouds where they land. He drops threat and basically just runs around wreaking havoc.[/li]\n[/ul]\n\nThe fight is relatively simple and can be completed by a group with as few as two well-geared players. Simply have one person in your party "tank" Hummel, applying [item=49351] to nullify the damage of his attacks and another player tank Baxter, using the [item=49352]. Frye cannot be tanked and will spend the entire fight throwing cologne/perfume bottles and switching aggro. None of the apothecaries deal significant melee damage (~300), and could probably be "tanked" by any class provided they''re wearing the appropriate scent. They can also be stunned, so a rogue can probably keep the more annoying Apothecary Frye stunlocked.\n\nThe other three players in your party can apply whichever scent they''d like, just being cautious to avoid opposite-colored clouds on the ground (they''re actually somewhat difficult to see, and cause ridiculous damage if you stand in them). Players should also try to stay away from the opposite-colored boss, as Hummel and Baxter have a melee-range aura that can cause serious damage if you''re in range too long. Also, "tanks" should face their apothecaries away from the rest of the group to avoid spraying them. If your poison or cologne buff runs out mid-fight simply use the item again to reapply the buff.\n\nThroughout the fight, both Hummel and Baxter will start working at small alchemy labs they pull out of who knows where, eventually causing a [spell=68821] which will hit anyone in the area for ~9k damage. Also, [npc=36568] will spawn endlessly, running wildly for a few seconds before exploding in a [spell=68957] dealing around ~3k damage to anybody nearby. These adds die upon exploding and cannot be tanked or controlled, so you''ll probably end up getting hit a few times.\n\nKill all three of the apothecaries (in any order), and the loot can be found on the body of Apothecary Hummel.\n\n[h3]Loot is in the Air[/h3]\n\n[img src=STATIC_URL/images/guide/love-is-in-the-air/crate.jpg border=0 float=right][b]Amulets[/b]\n[npc=36296] drops epic quality (item level 226) amulets which are the equivalent of Wrath of the Lich King''s second tier [item=45624] neckpieces. \n[ul]\n[li][item=51804] ([item=45823])[/li]\n[li][item=51805] ([item=45822])[/li]	\n[li][item=51806] ([item=45821])[/li]	\n[li][item=51807] ([item=45820])[/li]\n[li][item=51808] ([item=45819])[/li]\n[/ul]\n\n[b]Seasonal Items[/b]\n[npc=36296] also drops some fun seasonal items, including a fancy rose for your character''s hair, a gas mask (YES!), a non-combat oozeling companion, and an item so powerful it can break your heart!\n[ul]\n[li][item=49715][/li]\n[li][item=50741][/li]\n[li][item=50446][/li]	\n[li][item=50471][/li]\n[/ul]\n\n[b]Big Love Rocket[/b]\nAs if those things were cool enough, [npc=36296] also has an extremely low chance to drop the most stylish flying mount ever - the [spell=71342]!\n\n[ul]\n[li][item=50250]\n[modelviewer npc=30989]Big Love Rocket[/modelviewer][/li]\n[/ul]\n\nUpon defeating the boss for the first time, he will drop a [item=49641] which starts the quest [quest=14483]. This quest has you return to Snap Snagglebolt in Orgrimmar or Snip Snagglebolt in Stormwind.\n\n[h2]Seasonal Goodies[/h2]\n\n[url=?item=22261][img src=STATIC_URL/images/guide/love-is-in-the-air/fool.jpg border=0 float=right][/url]In the previous years, most of the fun, seasonal items were only obtained through random chance from Gifts and Pledges of Adoration and required extremely overcomplicated collection of items from all across Azeroth. As a result, many of the achievements and items related to them were a complete pain to get due to low drop rates and getting unlucky.\n\nIn light of this, Blizzard has instead opted to make most of the items required for these achievements purchasable from new seasonal vendors, using a new currency - [item=49927]. This currency can be acquired through completion of the newly-added daily quests.\n\n[npc=37674]s can be found in every capital city selling seasonal goodies:\n[pad]\n[table class=grid width=40%]\n[tr][td][b]Item[/b][/td][td align=center width=25%][b]Cost[/b][/td][/tr]\n[tr][td][item=49927][/td][td align=center][money=0 items=49916,1][/td][/tr]\n[tr][td]5x [item=49859] [small](+75 attack power)[/small][/td][td align=center][money=0 items=49927,1][/td][/tr]\n[tr][td]5x [item=49861] [small](+20 defense rating)[/small][/td][td align=center][money=0 items=49927,1][/td][/tr]\n[tr][td]5x [item=49860] [small](+45 spellpower)[/small][/td][td align=center][money=0 items=49927,1][/td][/tr]\n[tr][td]5x [item=49857] [small](+45 spellpower)[/small][/td][td align=center][money=0 items=49927,1][/td][/tr]\n[tr][td]5x [item=49858] [small](+20 defense rating)[/small][/td][td align=center][money=0 items=49927,1][/td][/tr]\n[tr][td]5x [item=49856] [small](+75 attack power)[/small][/td][td align=center][money=0 items=49927,1][/td][/tr]\n[tr][td][item=21813][/td][td align=center][money=0 items=49927,2][/td][/tr]\n[tr][td]5x [item=22218][/td][td align=center][money=0 items=49927,2][/td][/tr]\n[tr][td][item=50163][/td][td align=center][money=0 items=49927,5][/td][/tr]\n[tr][td]5x [item=34258][/td][td align=center][money=0 items=49927,5][/td][/tr]\n[tr][td]5x [item=22200][/td][td align=center][money=0 items=49927,5][/td][/tr]\n[tr][td][item=34480][/td][td align=center][money=0 items=49927,10][/td][/tr]\n[tr][td][item=21812][/td][td align=center][money=0 items=49927,10][/td][/tr]\n[tr][td][item=22261][/td][td align=center][money=0 items=49927,10][/td][/tr]\n[tr][td][item=50161][/td][td align=center][money=0 items=49927,20][/td][/tr]\n[tr][td][item=50160][/td][td align=center][money=0 items=49927,20][/td][/tr]\n[tr][td][item=22235][/td][td align=center][money=0 items=49927,40][/td][/tr]\n[/table]\n\n[h2]Achievements[/h2]\n[img src=STATIC_URL/images/guide/love-is-in-the-air/cupid.gif border=0 float=right]With each new event comes new achievements! For Love in the Air, there are 12 different challenges for players and a new player title granted to those who can achieve them all - [i]the Love Fool[/i]! Thankfully, many of these achievements should be significantly easier than they were in previous years!\n[ul]\n[li][b][icon name=side_horde][achievement=1693][/icon][/b] or [b][icon name=side_alliance][achievement=1707][/icon][/b]\nThis achievement can be found in the main World Events achievement category and is awarded upon completion of every Love is in the Air achievement [i]except[/i] [achievement=1700], [achievement=4624] and [achievement=1694]. These achievements should be easier this year as most items required can now be purchased from seasonal vendors. This achievement awards the player title ''The Love Fool'' and is a requirement towards completion of [achievement=2145] ([url=?achievement=2144]Alliance version[/url]) which rewards the [item=44177].[pad][/li]\n\n[li][b][achievement=1701][/b]\n[small][b]Eat the eight "Bag of Candies" heart candies listed below.[/b][/small]\nFor this achievement, you must eat one of each of the randomly generated message candies found inside a [item=21813]. The [item=21813] has 10 charges, and it can be purchased from a [npc=37674].[pad][/li]\n\n[li][b][achievement=260][/b]\n[small][b]Create 12 Lovely Charm Bracelets.[/b][/small]\nFor this achievement, you must create a total of 12 [item=49916], which are created by combining 10 [item=49655]s each. In order to acquire these charms, you must obtain a [item=49661] from Kwee Q. Peddlefeet located at the Crown Chemical Co.''s camps found outside of major city auction houses.[pad][/li]\n\n[li][b][achievement=1695][/b]\n[small][b]Assist the Steamwheedle Cartel in stopping the sinister Crown Chemical Co. plot.[/b][/small]\nFor this achievement, you must complete one of the [url=/?search=Crushing+the+Crown]Crushing the Crown[/url] daily quests offered by [npc=37172] in Orgrimmar or Inspector Snip Snagglebolt in Stormwind. There is a specific daily quest available to characters of every level range, with the lowest level quest being made available to players at least level 5 and the highest to players level 71 or above. This quest simply requires you to destroy a chemical wagon and kill five Crown Chemical Co. baddies found around it.[pad][/li]\n\n[li][b][achievement=1699][/b]\n[small][b]Use a Handful of Rose Petals on each of the race/class combinations listed below.[/b][/small]\nFor this achievement, you must use a [item=22218] on each of the following race/class combinations. The [item=22218] can be purchased with [item=49927] from a [npc=37674].\n[table width=70%]\n[tr] [td width=5%][/td][td][icon name=achievement_character_gnome_male][icon name=class_warlock][color=c9]Gnome Warlock[/color][/icon][/icon][/td][td][icon name=achievement_character_orc_male][icon name=class_deathknight][color=c6]Orc Death Knight[/color][/icon][/icon][/td][/td][/tr]\n\n[tr] [td width=5%][/td][td][icon name=achievement_character_human_male][icon name=class_deathknight][color=c6]Human Death Knight[/color][/icon][/icon][/td][td][icon name=achievement_character_nightelf_male][icon name=class_priest][color=c5]Night Elf Priest[/color][/icon][/icon][/td][/td][/tr]\n\n[tr] [td width=5%][/td][td][icon name=achievement_character_orc_male][icon name=class_shaman][color=c7]Orc Shaman[/color][/icon][/icon][/td][td][icon name=achievement_character_tauren_male][icon name=class_druid][color=c11]Tauren Druid[/color][/icon][/icon][/td][/td][/tr]\n\n[tr] [td width=5%][/td][td][icon name=achievement_character_undead_male][icon name=class_warrior][color=c1]Undead Warrior[/color][/icon][/icon][/td][td][icon name=achievement_character_troll_male][icon name=class_rogue][color=c4]Troll Rogue[/color][/icon][/icon][/td][/td][/tr]\n\n[tr] [td width=5%][/td][td][icon name=achievement_character_bloodelf_male][icon name=class_mage][color=c8]Blood Elf Mage[/color][/icon][/icon][/td][td][icon name=achievement_character_draenei_male][icon name=class_paladin][color=c2]Draenei Paladin[/color][/icon][/icon][/td][/td][/tr]\n\n[tr] [td width=5%][/td][td][icon name=achievement_character_dwarf_male][icon name=class_hunter][color=c3]Dwarf Hunter[/color][/icon][/icon][/td][td][/td][/td][/tr]\n[/table]\n[pad][/li]\n\n[li][icon name=side_horde][b][achievement=1280][/b][/icon] or [icon name=side_alliance][b][achievement=1279][/b][/icon]\n[small][b]Get completely smashed, put on your best perfume, throw a handful of rose petals on Jeremiah Payson or Sraaz and then kiss him. You''ll regret it in the morning.[/b][/small]\nTo complete this achievement, Horde players must get completely smashed, use one of the seasonal perfumes, throw a [item=22218] on [url=?npc=8403]Jeremiah Payson[/url] and the /kiss him. Alliance players must get completely smashed, use one of the seasonal perfumes, throw a [item=22218] on [url=?npc=9099]Sraaz[/url] and then /kiss him. Obviously the best way to get completely smashed would be through massive consumption of [spell=11009], but enough of any alcoholic beverage will do the trick. Simply drink to your heart''s content until you receive the message that your character is smashed, and you''re set! [item=22218] and your choice of a perfume can be purchased from a [npc=37674].[pad][/li]\n\n[li][b][achievement=1704][/b]\n[small][b]Pity the Love Fool in the locations specified below.[/b][/small]\nFor this achievement, you (or another player) must use [item=22261] in each of the five listed zones, and then /pity the Love Fool that is created. The zones in which you must do this are [zone=4197], [url=?zone=3358]Arathi Basin Blacksmith[/url], [zone=3456], [url=?zone=33]Battle Ring of Gurubashi Arena[/url] and [zone=4100]. The [item=22261] can be purchased from a [npc=37674].[pad][/li]\n\n[li][b][achievement=1291][/b]\n[img src=STATIC_URL/images/guide/love-is-in-the-air/picnic.jpg border=0 float=right][small][b]Enjoy a Buttermilk Delight with someone in Dalaran at a Romantic Picnic during the Love is in the Air celebration.[/b][/small]\nFor this achievement, you can either join someone in Dalaran who has used their [item=34480], or you can use your own and have someone else join you. Once you have used the Romantic Picnic and acquired the buff, you must then eat a [item=22236] candy, which can be obtained from a [item=21812].[pad][/li]\n\n[li][b][achievement=1694][/b]\n[small][b]Open a Lovely Dress Box and receive a Lovely Black Dress.[/b][/small]\nFor this achievement, you must loot a Lovely Black Dress from a Lovely Dress Box, which I assume has a chance to drop any of the [url=/?search=lovely+dress]Lovely Dresses[/url]. This item can be purchased from a [npc=37674].[pad][/li]\n\n[li][b][achievement=1703][/b]\n[small][b]Obtain a Bouquet of Red or Ebon Roses during the Love is in the Air celebration.[/b][/small]\nFor this achievement, you need to obtain either a [item=22206] or [item=44731]. Both of these have a random chance of dropping from [npc=27975] in [zone=4264], [npc=23953] in [zone=206] or [npc=29308] in [zone=4494] in either Normal or Heroic difficulty.[pad][/li]\n\n[li][icon name=side_horde][b][achievement=1698][/b][/icon] or [icon name=side_alliance][b][achievement=1697][/b][/icon]\n[small][b]Complete the Lovely Charm Bracelet daily quest for each Horde or Alliance capital.[/b][/small]\nFor this achievement, you must complete each of the different [url=/?search=A+Gift+for+the+]''A Gift for the...''[/url] quests available to your faction. To do this, you must obtain a [item=49661], collect a total of 40 [item=49655]s and create 4 Lovely Charm Bracelets, one for each of your faction''s leaders. This shouldn''t be a problem, as you will already want to be creating the Lovely Charm Bracelets for [achievement=260] and will want to complete these dailies to earn enough [item=49927] to purchase necessary event items![pad][/li]\n\n[li][b][achievement=1700][/b]\n[small][b]Obtain a permanent Peddlefeet pet by procuring a Truesilver Shafted Arrow.[/b][/small]\nFor this achievement, you must purchase the [item=22235] with [item=49927] from a [npc=37674]. This item will teach you to summon the companion pet [spell=27570].[pad][/li]\n\n[li][b][achievement=1188][/b]\n[small][b]Shoot 10 players with the Silver Shafted Arrow.[/b][/small]\nFor this achievement, all you have to do is use a [item=22200] on 10 players. You can purchase [item=22200] from a [npc=37674].[pad][/li]\n\n[li][b][achievement=1702][/b]\n[small][b]Sample the Love is in the Air candies listed below.[/b][/small]\nFor this achievement, you need to consume each of the four candies found within [item=21812].[pad][/li]\n\n[li][b][achievement=1696][/b]\n[small][b]Shoot off 10 Love Rockets in 20 seconds or less.[/b][/small]\nFor this achievement, you need to use 10 [item=34258] in 20 seconds (or less). Simply hotkey the rockets and spam away! The [item=34258] can be purchased from a [npc=37674].[pad][/li]\n\n[li][b][achievement=4624][/b]\n[small][b]Defeat the trio of Crown Chemical Co. apothecaries in Shadowfang Keep.[/b][/small]\nFor this achievement, you must complete the quest [quest=14488] inside [zone=209] and defeat [npc=36296] and his cronies. This is an event-only boss, similar to [npc=23872] during [url=/?event=372]Brewfest[/url].[pad][/li]\n\n[li][b][achievement=4627][/b]\n[small][b]Obtain the Big Love Rocket from Apothecary Hummel in Shadowfang Keep during Love is in the Air.[/b][/small]\nThis is not an achievement, but a [i]Feat of Strength[/i] awarded for obtaining the extremely rare Big Love Rocket, dropped by the event-only boss [npc=36296] in Shadowfang Keep. Spawning him will requires completion of a daily quest, limiting attempts to get this awesome ride, so good luck![/li]\n[/ul]'),
    (300,4,0,'midsummer-fire-festival','[menu tab=6 path=6,3,midsummer-fire-festival]\n\n[i][url=event=341]Midsummer[/url] is here! There are bonfires located in each major capital city (and throughout the world), which are surrounded by questgivers, [npc=16781], and a [icon name=side_alliance][npc=26123][/icon] or [icon name=side_horde][npc=26124][/icon] who sells items in exchange for [item=23247]. There are commoner NPCs of all races (including goblins!) that can be found lingering around the major cities and will give you a short (though unnecessary) quest to turn in at one of the main bonfire camps.[/i]\n\nAcquire [url=?item=34683]flaming[/url] [url=?item=34685]threads[/url], a fiery [url=?item=34955]companion[/url], epic cloaks and more! Complete achievements to earn a new player title. Horde players can obtain the title Flame Keeper and Alliance players can obtain the title Flame Warden.\n\n[h2]Festival Bonfires[/h2]\n\n[div class=minibox style="text-align:left"][toc h3=false][/div]\n\n[img src=STATIC_URL/images/guide/midsummer-fire-festival/bonfire.jpg float=right border=0]There are a total of 78 festival bonfires spread throughout Kalimdor, Eastern Kingdoms, Outland and Northrend: 40 for the Alliance and 38 for the Horde. Honor your faction''s flames, and desecrate the enemy''s! \n\nNot only does visiting these fires grant a [i]ton[/i] of money for level 80 characters, it is also extremely good experience for pre-80 characters (the experience gain will typically scale according to your level)! Considering the great experience for little effort and the character buffs detailed further below, this is a great opportunity for some easy experience! :)\n\nYou are also invited to go and steal the 4 flames of the opposing faction!\n\n[h3]Kalimdor, Eastern Kingdoms, Outland and Northrend[/h3]\n\n[ul]\n[li][b][url=?search&q=Honor+the+Flame#quests]Honor the Flame![/url][/b] - Awards [item=23247] x5, and [money=66300] at level 80\n[b]Start & End:[/b] [url=?search=Flame+Keeper]Flame Keeper[/url] located near each bonfire of your faction.\nThis quest can only be completed once per location at festival fires belonging to [b]your faction[/b].[pad][/li]\n[li][b][url=?search&q=Desecrate+this+Fire#quests]Desecrate this Fire![/url][/b] - Awards [item=23247] x10, and [money=132300] at level 80\n[b]Start:[/b] Each opposing faction bonfire.\n[b]End:[/b] [icon name=side_horde][npc=16818][/icon] or [icon name=side_alliance][npc=16817][/icon]\nThis quest can only be completed once per location at festival fires belonging to [b]the opposite faction[/b].[/li]\n[/ul]\n\n[h3]Enemy Capital Cities[/h3]\n\n[ul]\n[li][b][url=?search&q=stealing+flame#quests]Stealing X''s Flame[/url][/b] - Awards [item=23247] x25, plus choice of consumable\n[b]Start:[/b] Each opposing faction bonfire located in an enemy capital city.\n[b]End:[/b] [icon name=side_horde][npc=16818][/icon] or [icon name=side_alliance][npc=16817][/icon]\nThis quest can only be completed once per enemy capital city (4 total).[/li]\n[/ul]\n\n[h3]Complete List[/h3]\n\n[i]Tip: Clicking on the coordinates in the tables below will open a map of the bonfire''s location in a lightbox![/i]\n\n[pad]\n\n[tabs name=Bonfires]\n\n[tab name=Kalimdor_(23)][minibox][h3]Legend[/h3]\n[img src=STATIC_URL/images/Mapper/pin-blue.png border=0] [url=#ka-a]Alliance[/url] (11)\n[img src=STATIC_URL/images/Mapper/pin-red.png border=0] [url=#ka-h]Horde[/url] (12)\n[img src=STATIC_URL/images/Mapper/pin-yellow.png border=0] [url=#ka-c]Capital cities[/url]\n[/minibox][map zone=-6]\n[pin x=47.7 y=41.7 type=3][b]Astranaar[/b]\n[color=q]Ashenvale[/color][/pin]\n[pin x=32.6 y=27.5 type=3][b]Azure Watch[/b]\n[color=q]Azuremyst Isle[/color][/pin]\n[pin x=30 y=19.6 type=3][b]Blood Watch[/b]\n[color=q]Bloodmyst Isle[/color][/pin]\n[pin x=45.9 y=25.6 type=3][b]Auberdine[/b]\n[color=q]Darkshore[/color][/pin]\n[pin x=42.8 y=51.6 type=3][b]Nijel''s Point[/b]\n[color=q]Desolace[/color][/pin]\n[pin x=58.8 y=67.1 type=3][b]Theramore Isle[/b]\n[color=q]Dustwallow Marsh[/color][/pin]\n[pin x=36.9 y=71.2 type=3][b]Feathermoon Stronghold[/b]\n[color=q]Feralas[/color][/pin]\n[pin x=45.2 y=79.2 type=3][b]Cenarion Hold[/b]\n[color=q]Silithus[/color][/pin]\n[pin x=56.7 y=82.3 type=3][b]Gadgetzan[/b]\n[color=q]Tanaris[/color][/pin]\n[pin x=42 y=11.2 type=3][b]Dolanaar[/b]\n[color=q]Teldrassil[/color][/pin]\n[pin x=60.2 y=23.1 type=3][b]Everlook[/b]\n[color=q]Winterspring[/color][/pin]\n\n[pin x=52.9 y=42.5 type=2][b]Splintertree Post[/b]\n[color=q]Ashenvale[/color][/pin]\n[pin x=38.4 y=58.4 type=2][b]Shadowprey Village[/b]\n[color=q]Desolace[/color][/pin]\n[pin x=58.6 y=48.5 type=2][b]Razor Hill[/b]\n[color=q]Durotar[/color][/pin]\n[pin x=54.4 y=65.6 type=2][b]Brackenwall Village[/b]\n[color=q]Dustwallow Marsh[/color][/pin]\n[pin x=45.9 y=70.2 type=2][b]Camp Mojache[/b]\n[color=q]Feralas[/color][/pin]\n[pin x=47.5 y=63.3 type=2][b]Bloodhoof Village[/b]\n[color=q]Mulgore[/color][/pin]\n[pin x=43.5 y=80 type=2][b]Cenarion Hold[/b]\n[color=q]Silithus[/color][/pin]\n[pin x=44.4 y=47.3 type=2][b]Sun Rock Retreat[/b]\n[color=q]Stonetalon Mountains[/color][/pin]\n[pin x=55.5 y=81.7 type=2][b]Gadgetzan[/b]\n[color=q]Tanaris[/color][/pin]\n[pin x=53.2 y=54.5 type=2][b]The Crossroads[/b]\n[color=q]The Barrens[/color][/pin]\n[pin x=53.3 y=74.7 type=2][b]Freewind Post[/b]\n[color=q]Thousand Needles[/color][/pin]\n[pin x=59.3 y=23.1 type=2][b]Everlook[/b]\n[color=q]Winterspring[/color][/pin]\n\n[pin x=30.5 y=27.1][b]Rut''theran Village[/b]\n[color=q]Darnassus[/color][/pin]\n[pin x=59.3 y=44.2][b]Valley of Wisdom[/b]\n[color=q]Orgrimmar[/color][/pin]\n[pin x=30.5 y=27.1][b]The Crystal Hall[/b]\n[color=q]The Exodar[/color][/pin]\n[pin x=48 y=57.6][b]Spirit Rise[/b]\n[color=q]Thunder Bluff[/color][/pin]\n[/map]\n\n[h3 id=ka-a][icon name=side_alliance][achievement=1023][/icon] / [icon name=side_horde][achievement=1032][/icon] (11)[/h3]\n\nThese are the Alliance bonfires located in Kalimdor. Honor them if you''re Alliance, 